  onDismiss: () => void;
  onSelectModality: (modality: RecommendedModality) => void;
}

const strengthColors = {
  strong: "from-emerald-500 to-green-600",
  moderate: "from-blue-500 to-indigo-600",
  emerging: "from-amber-500 to-orange-600"
};

const strengthLabels = {
  strong: "Strong",
  moderate: "Moderate",
  emerging: "Emerging"
};

