  --color-sidebar-primary-foreground: hsl(var(--sidebar-primary-foreground));
  --color-sidebar-accent: hsl(var(--sidebar-accent));
  --color-sidebar-accent-foreground: hsl(var(--sidebar-accent-foreground));
  --color-sidebar-border: hsl(var(--sidebar-border));
  --color-sidebar-ring: hsl(var(--sidebar-ring));

  --font-sans: 'Inter', sans-serif;
  --font-heading: 'Space Grotesk', sans-serif;

  --radius: 0.75rem;
}

:root {
  /* SoulSanctuary AI Theme - Progressive Modern Church */
  /* Deep rich colors inspired by stained glass, warm wood, sacred spaces */
  --background: 270 15% 97%;
  --foreground: 270 25% 12%;

  --card: 0 0% 100%;
  --card-foreground: 270 25% 12%;

  --popover: 0 0% 100%;
  --popover-foreground: 270 25% 12%;

  --primary: 270 60% 45%; /* Deep Royal Purple - sanctuary, wisdom */
  --primary-foreground: 45 100% 96%;

  --secondary: 35 45% 92%; /* Warm cream - like candlelight */
  --secondary-foreground: 270 25% 15%;

  --muted: 270 10% 94%;
  --muted-foreground: 270 10% 45%;

  --accent: 45 80% 55%; /* Gold - divine, sacred, uplifting */
  --accent-foreground: 270 30% 15%;

  --destructive: 0 72% 51%;
  --destructive-foreground: 0 0% 98%;

  --border: 270 15% 88%;
  --input: 270 15% 90%;
  --ring: 270 60% 45%;

  --radius: 0.625rem;

  --sidebar: 270 35% 15%; /* Deep purple-gray like church shadows */
  --sidebar-foreground: 45 30% 95%;
  --sidebar-primary: 45 80% 55%; /* Gold accent */
  --sidebar-primary-foreground: 270 30% 12%;
  --sidebar-accent: 270 25% 22%;
  --sidebar-accent-foreground: 45 30% 95%;
  --sidebar-border: 270 20% 25%;
  --sidebar-ring: 45 80% 55%;

  /* Chart colors - stained glass inspired */
  --chart-1: 270 60% 50%; /* Purple */
  --chart-2: 45 80% 55%; /* Gold */
  --chart-3: 200 70% 45%; /* Deep blue */
  --chart-4: 340 65% 55%; /* Rose/burgundy */
  --chart-5: 160 50% 40%; /* Deep teal */
}

.dark {
  /* Dark mode - Evening sanctuary, candlelit warmth */
  --background: 270 25% 8%;
  --foreground: 45 20% 95%;

  --card: 270 20% 12%;
  --card-foreground: 45 20% 95%;

  --popover: 270 20% 12%;
  --popover-foreground: 45 20% 95%;

  --primary: 270 55% 55%; /* Lighter purple for dark mode */
  --primary-foreground: 270 25% 8%;

  --secondary: 270 15% 18%;
  --secondary-foreground: 45 20% 95%;

  --muted: 270 15% 18%;
  --muted-foreground: 270 10% 60%;

  --accent: 45 75% 50%; /* Warm gold glow */
  --accent-foreground: 270 25% 8%;

  --destructive: 0 55% 45%;
  --destructive-foreground: 0 0% 98%;

  --border: 240 3.7% 15.9%;
  --input: 240 3.7% 15.9%;
  --ring: 221 83% 53%;
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply font-sans antialiased bg-background text-foreground;
  }
  h1, h2, h3, h4, h5, h6 {
    @apply font-heading tracking-tight;
  }
}

@layer utilities {
  .minimal-scroll::-webkit-scrollbar {
    width: 6px;
  }
  .minimal-scroll::-webkit-scrollbar-track {
    background: transparent;
  }
  .minimal-scroll::-webkit-scrollbar-thumb {
    background: hsl(var(--muted-foreground) / 0.3);
    border-radius: 10px;
  }
}

