const HARMFUL_THINKING_PATTERNS: Record<string, string[]> = {
  racism: [
    "those people", "all of them are", "they're all the same",
    "their kind", "they're ruining", "go back to",
    "shouldn't be allowed", "inferior race", "superior race"
  ],
