import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Slider } from "@/components/ui/slider";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Plus, Trash2, Flag, Percent, Users } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useTranslation } from "react-i18next";
import type { FeatureFlag } from "@shared/schema";

export default function FeatureFlags() {
  const { toast } = useToast();
  const { t } = useTranslation();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [newFlag, setNewFlag] = useState({
    key: "",
    name: "",
    description: "",
    enabled: false,
    rolloutPercentage: 0,
  });

  const { data: flags = [], isLoading } = useQuery<FeatureFlag[]>({
    queryKey: ["/api/feature-flags"],
  });

  const createMutation = useMutation({
    mutationFn: async (data: typeof newFlag) => {
      return await apiRequest("POST", "/api/feature-flags", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/feature-flags"] });
      setDialogOpen(false);
      setNewFlag({ key: "", name: "", description: "", enabled: false, rolloutPercentage: 0 });
      toast({ title: t('featureFlags.created') });
    },
    onError: (error: any) => {
      toast({ title: t('featureFlags.errorCreate'), description: error.message, variant: "destructive" });
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, updates }: { id: number; updates: Partial<FeatureFlag> }) => {
      return await apiRequest("PATCH", `/api/feature-flags/${id}`, updates);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/feature-flags"] });
      toast({ title: t('featureFlags.updated') });
    },
    onError: (error: any) => {
      toast({ title: t('featureFlags.errorUpdate'), description: error.message, variant: "destructive" });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: number) => {
      return await apiRequest("DELETE", `/api/feature-flags/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/feature-flags"] });
      toast({ title: t('featureFlags.deleted') });
    },
    onError: (error: any) => {
      toast({ title: t('featureFlags.errorDelete'), description: error.message, variant: "destructive" });
    },
  });

  const handleToggle = (flag: FeatureFlag) => {
    updateMutation.mutate({ id: flag.id, updates: { enabled: !flag.enabled } });
  };

  const handleRolloutChange = (flag: FeatureFlag, value: number[]) => {
    updateMutation.mutate({ id: flag.id, updates: { rolloutPercentage: value[0] } });
  };

  const handleCreate = () => {
    if (!newFlag.key || !newFlag.name) {
      toast({ title: t('featureFlags.requiredFields'), variant: "destructive" });
      return;
    }
    createMutation.mutate(newFlag);
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <div className="flex items-center justify-between gap-4 mb-6">
        <div>
          <h1 className="text-2xl font-semibold flex items-center gap-2" data-testid="text-page-title">
            <Flag className="h-6 w-6" />
            {t('featureFlags.title')}
          </h1>
          <p className="text-muted-foreground mt-1">
            {t('featureFlags.subtitle')}
          </p>
        </div>

        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger asChild>
            <Button data-testid="button-create-flag">
              <Plus className="h-4 w-4 mr-2" />
              {t('featureFlags.newFlag')}
            </Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>{t('featureFlags.createFlag')}</DialogTitle>
            </DialogHeader>
            <div className="space-y-4 mt-4">
              <div className="space-y-2">
                <Label htmlFor="key">{t('featureFlags.key')}</Label>
                <Input
                  id="key"
                  data-testid="input-flag-key"
                  placeholder={t('featureFlags.keyPlaceholder')}
                  value={newFlag.key}
                  onChange={(e) => setNewFlag({ ...newFlag, key: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="name">{t('featureFlags.name')}</Label>
                <Input
                  id="name"
                  data-testid="input-flag-name"
                  placeholder={t('featureFlags.namePlaceholder')}
                  value={newFlag.name}
                  onChange={(e) => setNewFlag({ ...newFlag, name: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="description">{t('featureFlags.description')}</Label>
                <Textarea
                  id="description"
                  data-testid="input-flag-description"
                  value={newFlag.description}
                  onChange={(e) => setNewFlag({ ...newFlag, description: e.target.value })}
                />
              </div>
              <div className="flex items-center justify-between">
                <Label htmlFor="enabled">{t('featureFlags.enabled')}</Label>
                <Switch
                  id="enabled"
                  data-testid="switch-flag-enabled"
                  checked={newFlag.enabled}
                  onCheckedChange={(checked) => setNewFlag({ ...newFlag, enabled: checked })}
                />
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label>{t('featureFlags.rollout')}</Label>
                  <span className="text-sm text-muted-foreground">{newFlag.rolloutPercentage}%</span>
                </div>
                <Slider
                  data-testid="slider-rollout"
                  value={[newFlag.rolloutPercentage]}
                  onValueChange={(value) => setNewFlag({ ...newFlag, rolloutPercentage: value[0] })}
                  max={100}
                  step={1}
                />
              </div>
              <Button
                className="w-full"
                data-testid="button-submit-flag"
                onClick={handleCreate}
                disabled={createMutation.isPending}
              >
                {createMutation.isPending ? t('common.loading') : t('featureFlags.createFlag')}
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {flags.length === 0 ? (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Flag className="h-12 w-12 text-muted-foreground mb-4" />
            <h3 className="text-lg font-medium mb-2">{t('featureFlags.noFlags')}</h3>
            <p className="text-muted-foreground text-center mb-4">
              {t('featureFlags.createFirst')}
            </p>
            <Button onClick={() => setDialogOpen(true)} data-testid="button-create-first-flag">
              <Plus className="h-4 w-4 mr-2" />
              {t('featureFlags.createFlag')}
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          {flags.map((flag) => (
            <Card key={flag.id} data-testid={`card-flag-${flag.id}`}>
              <CardHeader className="flex flex-row items-center justify-between gap-4 pb-2">
                <div className="flex-1">
                  <div className="flex items-center gap-2 flex-wrap">
                    <CardTitle className="text-base">{flag.name}</CardTitle>
                    <Badge variant="outline">
                      {flag.key}
                    </Badge>
                    {flag.enabled ? (
                      <Badge className="bg-green-500/10 text-green-600 border-green-500/20">
                        {t('featureFlags.active')}
                      </Badge>
                    ) : (
                      <Badge variant="secondary">
                        {t('featureFlags.inactive')}
                      </Badge>
                    )}
                  </div>
                  {flag.description && (
                    <p className="text-sm text-muted-foreground mt-1">{flag.description}</p>
                  )}
                </div>
                <div className="flex items-center gap-2">
                  <Switch
                    data-testid={`switch-toggle-${flag.id}`}
                    checked={flag.enabled ?? false}
                    onCheckedChange={() => handleToggle(flag)}
                    disabled={updateMutation.isPending}
                  />
                  <Button
                    size="icon"
                    variant="ghost"
                    data-testid={`button-delete-${flag.id}`}
                    onClick={() => deleteMutation.mutate(flag.id)}
                    disabled={deleteMutation.isPending}
                  >
                    <Trash2 className="h-4 w-4 text-destructive" />
                  </Button>
                </div>
              </CardHeader>
              <CardContent>
                <div className="flex items-center gap-4">
                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Percent className="h-4 w-4" />
                    <span>{t('featureFlags.rollout')}: {flag.rolloutPercentage ?? 0}%</span>
                  </div>
                  <div className="flex-1 max-w-xs">
                    <Slider
                      data-testid={`slider-rollout-${flag.id}`}
                      value={[flag.rolloutPercentage ?? 0]}
                      onValueCommit={(value) => handleRolloutChange(flag, value)}
                      max={100}
                      step={1}
                      disabled={updateMutation.isPending}
                    />
                  </div>
                  {flag.userSegments && flag.userSegments.length > 0 && (
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <Users className="h-4 w-4" />
                      <span>{flag.userSegments.length} {t('featureFlags.segments')}</span>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

client/src/components/LanguageSwitcher.t.content:
import { useTranslation } from 'react-i18next';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Globe } from "lucide-react";

const languages = [
  { code: 'en', name: 'English', nativeName: 'English' },
  { code: 'es', name: 'Spanish', nativeName: 'Español' },
  { code: 'pt', name: 'Portuguese', nativeName: 'Português' },
];

export function LanguageSwitcher() {
  const { i18n, t } = useTranslation();

  const changeLanguage = (lng: string) => {
    i18n.changeLanguage(lng);
  };

  const currentLanguage = languages.find(l => l.code === i18n.language) || languages[0];

  return (
    <div className="flex items-center gap-2">
      <Globe className="h-4 w-4 text-muted-foreground" />
      <Select value={i18n.language} onValueChange={changeLanguage}>
        <SelectTrigger className="w-[140px]" data-testid="select-language">
          <SelectValue placeholder={currentLanguage.nativeName} />
        </SelectTrigger>
        <SelectContent>
          {languages.map((lang) => (
            <SelectItem 
              key={lang.code} 
              value={lang.code}
              data-testid={`option-lang-${lang.code}`}
            >
              {lang.nativeName}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </div>
  );
}

client/src/pages/ClinicianDashboard.tsx.content:
import { Layout } from "@/components/layout/Layout";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { useState } from "react";
import { 
  Users, Calendar, ClipboardList, Plus, Play, CheckCircle, 
  Clock, FileText, TrendingUp, UserCircle, Stethoscope
} from "lucide-react";
import type { ClinicianSession } from "@shared/schema";

export default function ClinicianDashboard() {
  const { toast } = useToast();
  const [isNewSessionOpen, setIsNewSessionOpen] = useState(false);
  const [newSession, setNewSession] = useState({
    anonPatientHash: "",
    sessionType: "ad_hoc",
    sessionNotes: ""
  });

  const { data: sessions = [], isLoading: sessionsLoading } = useQuery<ClinicianSession[]>({
    queryKey: ['/api/clinician/sessions']
  });

  const { data: stats, isLoading: statsLoading } = useQuery<{
    totalSessions: number;
    activeSessions: number;
    completedSessions: number;
    patientCount: number;
  }>({
    queryKey: ['/api/clinician/stats']
  });

  const createSessionMutation = useMutation({
    mutationFn: async (data: typeof newSession) => {
      return await apiRequest('POST', '/api/clinician/sessions', data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/clinician/sessions'] });
      queryClient.invalidateQueries({ queryKey: ['/api/clinician/stats'] });
      setIsNewSessionOpen(false);
      setNewSession({ anonPatientHash: "", sessionType: "ad_hoc", sessionNotes: "" });
      toast({ title: "Session created successfully" });
    },
    onError: (error: any) => {
      toast({ title: "Failed to create session", description: error.message, variant: "destructive" });
    }
  });

  const updateSessionMutation = useMutation({
    mutationFn: async ({ id, updates }: { id: number; updates: Partial<ClinicianSession> }) => {
      return await apiRequest('PATCH', `/api/clinician/sessions/${id}`, updates);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/clinician/sessions'] });
      queryClient.invalidateQueries({ queryKey: ['/api/clinician/stats'] });
      toast({ title: "Session updated" });
    },
    onError: (error: any) => {
      toast({ title: "Failed to update session", description: error.message, variant: "destructive" });
    }
  });

  const handleStartSession = (id: number) => {
    updateSessionMutation.mutate({ 
      id, 
      updates: { status: 'in_progress', startedAt: new Date() } 
    });
  };

  const handleCompleteSession = (id: number) => {
    updateSessionMutation.mutate({ 
      id, 
      updates: { status: 'completed', endedAt: new Date() } 
    });
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'scheduled':
        return <Badge variant="outline" className="text-blue-600 border-blue-300"><Clock className="w-3 h-3 mr-1" />Scheduled</Badge>;
      case 'in_progress':
        return <Badge className="bg-green-500"><Play className="w-3 h-3 mr-1" />In Progress</Badge>;
      case 'completed':
        return <Badge variant="secondary"><CheckCircle className="w-3 h-3 mr-1" />Completed</Badge>;
      default:
        return <Badge variant="outline">{status}</Badge>;
    }
  };

  return (
    <Layout>
      <div className="flex-1 overflow-auto p-6">
        <div className="max-w-6xl mx-auto space-y-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold flex items-center gap-2" data-testid="text-clinician-title">
                <Stethoscope className="h-6 w-6 text-primary" />
                Clinician Dashboard
              </h1>
              <p className="text-muted-foreground mt-1">Manage patient sessions and track outcomes</p>
            </div>

            <Dialog open={isNewSessionOpen} onOpenChange={setIsNewSessionOpen}>
              <DialogTrigger asChild>
                <Button data-testid="button-new-session">
                  <Plus className="w-4 h-4 mr-2" />
                  New Session
                </Button>
              </DialogTrigger>
              <DialogContent>
                <DialogHeader>
                  <DialogTitle>Create New Session</DialogTitle>
                  <DialogDescription>Schedule a new patient session</DialogDescription>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div className="space-y-2">
                    <Label htmlFor="patientId">Patient Identifier</Label>
                    <Input
                      id="patientId"
                      placeholder="Anonymous patient hash or ID"
                      value={newSession.anonPatientHash}
                      onChange={(e) => setNewSession(prev => ({ ...prev, anonPatientHash: e.target.value }))}
                      data-testid="input-patient-id"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="sessionType">Session Type</Label>
                    <Select 
                      value={newSession.sessionType} 
                      onValueChange={(v) => setNewSession(prev => ({ ...prev, sessionType: v }))}
                    >
                      <SelectTrigger data-testid="select-session-type">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="ad_hoc">Ad Hoc</SelectItem>
                        <SelectItem value="scheduled">Scheduled</SelectItem>
                        <SelectItem value="follow_up">Follow Up</SelectItem>
                        <SelectItem value="intake">Intake</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="notes">Initial Notes</Label>
                    <Textarea
                      id="notes"
                      placeholder="Session notes..."
                      value={newSession.sessionNotes}
                      onChange={(e) => setNewSession(prev => ({ ...prev, sessionNotes: e.target.value }))}
                      data-testid="input-session-notes"
                    />
                  </div>
                </div>
                <DialogFooter>
                  <Button variant="outline" onClick={() => setIsNewSessionOpen(false)} data-testid="button-cancel-session">Cancel</Button>
                  <Button 
                    onClick={() => createSessionMutation.mutate(newSession)}
                    disabled={!newSession.anonPatientHash || createSessionMutation.isPending}
                    data-testid="button-create-session"
                  >
                    {createSessionMutation.isPending ? "Creating..." : "Create Session"}
                  </Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
                <CardTitle className="text-sm font-medium">Total Sessions</CardTitle>
                <ClipboardList className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="text-total-sessions">
                  {statsLoading ? "..." : stats?.totalSessions ?? 0}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
                <CardTitle className="text-sm font-medium">Active Sessions</CardTitle>
                <Play className="h-4 w-4 text-green-500" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-green-600" data-testid="text-active-sessions">
                  {statsLoading ? "..." : stats?.activeSessions ?? 0}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
                <CardTitle className="text-sm font-medium">Completed</CardTitle>
                <CheckCircle className="h-4 w-4 text-blue-500" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-blue-600" data-testid="text-completed-sessions">
                  {statsLoading ? "..." : stats?.completedSessions ?? 0}
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between gap-2 pb-2">
                <CardTitle className="text-sm font-medium">Patients</CardTitle>
                <Users className="h-4 w-4 text-purple-500" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-purple-600" data-testid="text-patient-count">
                  {statsLoading ? "..." : stats?.patientCount ?? 0}
                </div>
              </CardContent>
            </Card>
          </div>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Calendar className="h-5 w-5" />
                Sessions
              </CardTitle>
              <CardDescription>View and manage your patient sessions</CardDescription>
            </CardHeader>
            <CardContent>
              {sessionsLoading ? (
                <div className="text-center py-8 text-muted-foreground">Loading sessions...</div>
              ) : sessions.length === 0 ? (
                <div className="text-center py-8">
                  <UserCircle className="h-12 w-12 mx-auto text-muted-foreground/50 mb-4" />
                  <p className="text-muted-foreground">No sessions yet</p>
                  <p className="text-sm text-muted-foreground/70 mt-1">Create your first session to get started</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {sessions.map((session) => (
                    <div 
                      key={session.id} 
                      className="flex items-center justify-between p-4 border rounded-lg"
                      data-testid={`card-session-${session.id}`}
                    >
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-primary/10 rounded-full">
                          <UserCircle className="h-5 w-5 text-primary" />
                        </div>
                        <div>
                          <div className="font-medium">Patient: {session.anonPatientHash.slice(0, 8)}...</div>
                          <div className="text-sm text-muted-foreground flex items-center gap-2">
                            <span className="capitalize">{session.sessionType?.replace('_', ' ')}</span>
                            <span>•</span>
                            <span>{new Date(session.createdAt).toLocaleDateString()}</span>
                          </div>
                        </div>
                      </div>

                      <div className="flex items-center gap-3">
                        {getStatusBadge(session.status || 'scheduled')}

                        {session.status === 'scheduled' && (
                          <Button 
                            size="sm" 
                            onClick={() => handleStartSession(session.id)}
                            disabled={updateSessionMutation.isPending}
                            data-testid={`button-start-session-${session.id}`}
                          >
                            <Play className="w-3 h-3 mr-1" />
                            Start
                          </Button>
                        )}

                        {session.status === 'in_progress' && (
                          <Button 
                            size="sm" 
                            variant="outline"
                            onClick={() => handleCompleteSession(session.id)}
                            disabled={updateSessionMutation.isPending}
                            data-testid={`button-complete-session-${session.id}`}
                          >
                            <CheckCircle className="w-3 h-3 mr-1" />
                            Complete
                          </Button>
                        )}

                        {session.sessionNotes && (
                          <Button size="icon" variant="ghost">
                            <FileText className="w-4 h-4" />
                          </Button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      </div>
    </Layout>
  );
}

